import React from 'react';

function Parallax({ scrollPercentage }) {
  return (
    <div className="Parallax">
      <div className="Layer1" style={{backgroundImage: `url('/pics/Layer0.webp')`, backgroundPositionY: -scrollPercentage * 0.2 + 'px'}}></div>
      <div className="Layer2" style={{backgroundImage: `url('/pics/Layer1.webp')`, backgroundPositionY: -scrollPercentage * 0.4 + 'px'}}></div>
      <div className="Layer3" style={{backgroundImage: `url('/pics/Layer2.webp')`, backgroundPositionY: -scrollPercentage * 0.6 + 'px'}}></div>
      <div className="Layer4" style={{backgroundImage: `url('/pics/Layer3.webp')`, backgroundPositionY: -scrollPercentage * 0.8 + 'px'}}></div>
      <div className="Layer5" style={{backgroundImage: `url('/pics/Layer4.webp')`, backgroundPositionY: -scrollPercentage * 1.0 + 'px'}}></div>
    </div>
  );
}

export default Parallax;
